 87→    handleRequest = async (endpoint, data) => {
 88→        const url = `/jsapi/${endpoint}`;
 89→        try {
 90→            const response = await fetch(url, {
 91→                method: "POST",
 92→                headers: {
 93→                    "Content-Type": "application/json",
 94→                },
 95→                body: JSON.stringify({
 96→                    developer: this.developer,
 97→                    version: this.version,
 98→                    data,
 99→                }),
100→            });
101→
102→            if (!response.ok) {
103→                throw new Error("Failed to make the request");
104→            }
105→
106→            const responseData = await response.text();
107→            if (endpoint.includes("nextTime") || endpoint.includes("deckName")) {
108→                return responseData;
109→            }
110→            return JSON.parse(responseData);
111→        } catch (error) {
112→            console.error("Request error:", error);
113→            throw error;
114→        }
115→    };
116→}
